mapper.update:
		UPDATE 
        	HC_DETECTION_LEVEL
        SET 
        	USE_STATUS = #{useStatus}
        	, UPD_MEM_ID = #{updMemId}
        	, UPD_DATE = SYSDATE()
        WHERE 
        	1=1
        	AND SEQ = #{seq}

INSERT INTO 
	HC_DETECTION_LEVEL_HISTORY
	(`LEVEL`
	, PREV_LEVEL
	, LEVEL_STRNG
	, PREV_LEVEL_STRNG
	, LEVEL_DESCRIPTION
	, PREV_LEVEL_DESCRIPTION
	, UPD_CLIENT_IP
	, LAST_MOD_MEM_ID
	, LAST_MOD_DATE)
VALUES(
	#{level}
	, #{prevLevel}
	, #{levelStrng}
	, #{prevLevelStrng}
	, #{levelDescription}
	, #{prevLevelDescription}
	, #{updClientIp}
	, #{lastModMemId}
	, sysdate())
